#include <stdio.h>
#include <string.h>
#include <stdlib.h>

typedef struct {
    int id;
    char name[101];
    char grade;
} Student;

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N;
        scanf("%d", &N);
        Student *students = (Student*)malloc(N * sizeof(Student));
        int cnt = 0;
        for (int i = 0; i < N; ++i) {
            char op[10];
            scanf("%s", op);
            if (strcmp(op, "add") == 0) {
                int id; char name[101]; char grade;
                scanf("%d %s %c", &id, name, &grade);
                students[cnt].id = id;
                strcpy(students[cnt].name, name);
                students[cnt].grade = grade;
                ++cnt;
            } else if (strcmp(op, "remove") == 0) {
                int id; scanf("%d", &id);
                for (int j = 0; j < cnt; ++j) {
                    if (students[j].id == id) {
                        for (int k = j; k < cnt - 1; ++k) {
                            students[k] = students[k + 1];
                        }
                        --cnt;
                        break;
                    }
                }
            } else if (strcmp(op, "display") == 0) {
                for (int j = 0; j < cnt; ++j) {
                    printf("ID: %d, Name: %s, Grade: %c\n", students[j].id, students[j].name, students[j].grade);
                }
            }
        }
        free(students);
    }
    return 0;
}

code.C++:
#include <bits/stdc++.h>
using namespace std;

class Student {
public:
    int id;
    string name;
    char grade;
    void display() const {
        cout << "ID: " << id << ", Name: " << name << ", Grade: " << grade << '\n';
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int T; if (!(cin >> T)) return 0;
    while (T--) {
        int N; cin >> N;
        vector<Student> students;
        for (int i = 0; i < N; ++i) {
            string op; cin >> op;
            if (op == "add") {
                Student s; cin >> s.id >> s.name >> s.grade;
                students.push_back(s);
            } else if (op == "remove") {
                int id; cin >> id;
                for (auto it = students.begin(); it != students.end(); ++it) {
                    if (it->id == id) { students.erase(it); break; }
                }
            } else if (op == "display") {
                for (const auto &s : students) s.display();
            }
        }
    }
    return 0;
}

