#!/usr/bin/env python3
import sys

def main():
    data = sys.stdin.read().splitlines()
    if not data:
        return
    idx = 0
    T = int(data[idx]); idx += 1
    out = []
    for _ in range(T):
        N = int(data[idx]); idx += 1
        students = []  # list of (id, name, grade)
        for _ in range(N):
            parts = data[idx].split(); idx += 1
            op = parts[0]
            if op == 'add':
                sid = int(parts[1]); name = parts[2]; grade = parts[3]
                students.append((sid, name, grade))
            elif op == 'remove':
                sid = int(parts[1])
                for i, (iid, _, _) in enumerate(students):
                    if iid == sid:
                        students.pop(i)
                        break
            elif op == 'display':
                for sid, name, grade in students:
                    out.append(f"ID: {sid}, Name: {name}, Grade: {grade}")
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    main()

